import math

x, y = map(int, input().split())

def f(x, y):
    if x == y:
        return 0
    if x > y:
        return f(y, x)
    if x == 1:
        return math.inf
    if x % 3 == 0:
        return 1 + f(x // 3, y)
    if x % 3 == 1:
        return 1 + min(f(x // 3 + 1, y), f(x // 3, y))
    if x % 3 == 2:
        return 1 + min(f(x // 3 + 1, y), f(x // 3 + 2, y))

print(f(x, y))
